import { useState } from 'react';
import { PipelineToolbar } from './toolbar';
import { PipelineUI } from './ui';
import { SubmitButton } from './submit';
import { Toaster } from 'react-hot-toast';
import { FlowStats } from './FlowStats';
import { SavedFlows } from './SavedFlows';
import { ClockIcon } from '@heroicons/react/24/outline';

function App() {
  const [isSavedFlowsOpen, setIsSavedFlowsOpen] = useState(false);

  return (
    <div className="flex flex-col-reverse md:flex-row h-screen w-screen overflow-hidden bg-[#020617] font-sans text-slate-200">
      <Toaster
        position="top-center"
        toastOptions={{
          style: {
            background: '#0D1117',
            color: '#e2e8f0',
            border: '1px solid #30363D',
            fontSize: '14px',
            borderRadius: '12px',
          },
          success: {
            iconTheme: {
              primary: '#10B981',
              secondary: '#fff',
            },
          },
        }}
      />

      <PipelineToolbar />

      <div className="flex-1 relative h-full w-full">
        <PipelineUI />

        <FlowStats />

        <div className="absolute top-4 right-4 md:top-6 md:right-6 z-10 flex items-center gap-3">
          <button
            onClick={() => setIsSavedFlowsOpen(true)}
            className="p-3 bg-[#050505]/80 hover:bg-[#8B5CF6]/20 border border-slate-700/50 hover:border-[#8B5CF6]/50 text-slate-300 hover:text-white rounded-lg shadow-xl backdrop-blur-md cursor-pointer flex gap-2 justify-center capitalize items-center transition-all duration-300 group"
            title="Execution History"
          >
            <ClockIcon className="w-5 h-5 group-hover:rotate-12 transition-transform" />
            <span className="hidden md:inline text-xs font-bold uppercase tracking-widest">History</span>
          </button>

          <SubmitButton />
        </div>

        <SavedFlows isOpen={isSavedFlowsOpen} onClose={() => setIsSavedFlowsOpen(false)} />
      </div>
    </div>
  );
}

export default App;
